/**
 * @summary Get aggregated analytics data (internal only)
 */
export const getGetAnalyticsDashboardUrl = (
  params?: GetAnalyticsDashboardParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/analytics?${stringifiedParams}`
    : `/api/admin/analytics`;
};

export const getAnalyticsDashboard = async (
  params?: GetAnalyticsDashboardParams,
  options?: RequestInit,
): Promise<AnalyticsDashboard> => {
  return customFetch<AnalyticsDashboard>(getGetAnalyticsDashboardUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetAnalyticsDashboardQueryKey = (
  params?: GetAnalyticsDashboardParams,
) => {
  return [`/api/admin/analytics`, ...(params ? [params] : [])] as const;
};

export const getGetAnalyticsDashboardQueryOptions = <
  TData = Awaited<ReturnType<typeof getAnalyticsDashboard>>,
  TError = ErrorType<ErrorEnvelope>,
>(
  params?: GetAnalyticsDashboardParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAnalyticsDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetAnalyticsDashboardQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getAnalyticsDashboard>>
  > = ({ signal }) =>
    getAnalyticsDashboard(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getAnalyticsDashboard>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAnalyticsDashboardQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAnalyticsDashboard>>
>;
export type GetAnalyticsDashboardQueryError = ErrorType<ErrorEnvelope>;

